-- Create "chat_sessions" table
CREATE TABLE "chat_sessions" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "session_key" character varying NOT NULL,
  "owner_subject" character varying NOT NULL,
  "status" character varying NOT NULL DEFAULT 'open',
  "turn_count" bigint NOT NULL DEFAULT 0,
  "started_at" timestamptz NOT NULL,
  "last_activity_at" timestamptz NOT NULL,
  "closed_at" timestamptz NULL,
  "close_reason" character varying NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "diagnosis_task_id" bigint NOT NULL,
  PRIMARY KEY ("id"),
  CONSTRAINT "chat_sessions_diagnosis_tasks_chat_sessions" FOREIGN KEY ("diagnosis_task_id") REFERENCES "diagnosis_tasks" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION
);
-- Create index "chat_sessions_session_key_key" to table: "chat_sessions"
CREATE UNIQUE INDEX "chat_sessions_session_key_key" ON "chat_sessions" ("session_key");
-- Create index "chatsession_diagnosis_task_id" to table: "chat_sessions"
CREATE UNIQUE INDEX "chatsession_diagnosis_task_id" ON "chat_sessions" ("diagnosis_task_id");
-- Create index "chatsession_owner_subject_status" to table: "chat_sessions"
CREATE INDEX "chatsession_owner_subject_status" ON "chat_sessions" ("owner_subject", "status");
-- Create index "chatsession_started_at" to table: "chat_sessions"
CREATE INDEX "chatsession_started_at" ON "chat_sessions" ("started_at");
-- Create index "chatsession_status_last_activity_at" to table: "chat_sessions"
CREATE INDEX "chatsession_status_last_activity_at" ON "chat_sessions" ("status", "last_activity_at");
-- Create "chat_turns" table
CREATE TABLE "chat_turns" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "message_id" character varying NOT NULL,
  "sequence" bigint NOT NULL,
  "role" character varying NOT NULL,
  "actor_subject" character varying NOT NULL,
  "content" text NOT NULL,
  "metadata" jsonb NULL,
  "occurred_at" timestamptz NOT NULL,
  "created_at" timestamptz NOT NULL,
  "chat_session_id" bigint NOT NULL,
  PRIMARY KEY ("id"),
  CONSTRAINT "chat_turns_chat_sessions_turns" FOREIGN KEY ("chat_session_id") REFERENCES "chat_sessions" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION
);
-- Create index "chatturn_chat_session_id_created_at" to table: "chat_turns"
CREATE INDEX "chatturn_chat_session_id_created_at" ON "chat_turns" ("chat_session_id", "created_at");
-- Create index "chatturn_chat_session_id_message_id" to table: "chat_turns"
CREATE UNIQUE INDEX "chatturn_chat_session_id_message_id" ON "chat_turns" ("chat_session_id", "message_id");
-- Create index "chatturn_chat_session_id_occurred_at" to table: "chat_turns"
CREATE INDEX "chatturn_chat_session_id_occurred_at" ON "chat_turns" ("chat_session_id", "occurred_at");
-- Create index "chatturn_chat_session_id_sequence" to table: "chat_turns"
CREATE UNIQUE INDEX "chatturn_chat_session_id_sequence" ON "chat_turns" ("chat_session_id", "sequence");
